import logging
import azure.functions as func
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from azure.identity import ManagedIdentityCredential

def main(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}")

    # Managed Identity Credential
    credential = ManagedIdentityCredential()

    # Blob Storage Client
    blob_service_client = BlobServiceClient(account_url="https://<your-storage-account-name>.blob.core.windows.net", credential=credential)
    container_client = blob_service_client.get_container_client("<your-container-name>")
    
    # Read blob data
    blob_data = myblob.read()
    logging.info(f"Blob data: {blob_data}")

    # Process data (example: convert to uppercase)
    processed_data = blob_data.decode('utf-8').upper()

    # Cosmos DB Client
    cosmos_client = CosmosClient("<your-cosmos-db-account-uri>", credential=credential)
    database_name = "<your-database-name>"
    container_name = "<your-container-name>"
    database = cosmos_client.get_database_client(database_name)
    container = database.get_container_client(container_name)

    # Write processed data to Cosmos DB
    container.upsert_item({
        'id': myblob.name,
        'content': processed_data
    })

    # Event Grid Client
    event_grid_client = EventGridPublisherClient(endpoint="<your-event-grid-topic-endpoint>", credential=credential)
    event = EventGridEvent(
        subject="BlobProcessed",
        event_type="BlobProcessedEvent",
        data={"blobName": myblob.name, "status": "Processed"},
        data_version="1.0"
    )

    # Send notification via Event Grid
    event_grid_client.send(event)
    logging.info("Notification sent via Event Grid")